module alu(
    input [31:0] a,
    input [31:0] b,
    input [5:0] aluc,
    output [31:0] r,
    output zero,
    output carry,
    output negative,
    output overflow,
    output flag
);

    // Internal signals
    wire [31:0] result;
    wire [31:0] add_result;
    wire [31:0] sub_result;
    wire [31:0] and_result;
    wire [31:0] or_result;
    wire [31:0] xor_result;
    wire [31:0] sl_result;
    wire [31:0] sr_result;
    wire [31:0] sra_result;
    wire [31:0] lui_result;
    wire [31:0] adder_result;
    wire [31:0] subtractor_result;
    wire adder_carry;
    wire subtractor_carry;
    wire overflow_detect;

    // Arithmetic and logic operations
    assign add_result = a + b;
    assign sub_result = a - b;
    assign and_result = a & b;
    assign or_result = a | b;
    assign xor_result = a ^ b;
    assign sl_result = a << b[4:0];
    assign sr_result = a >> b[4:0];
    assign sra_result = $signed(a) >>> b[4:0];
    assign lui_result = {b[15:0], 16'b0};

    // Adder and subtractor
    assign adder_result = a + b;
    assign subtractor_result = a - b;
    assign adder_carry = (a[31] & b[31]) | (a[31] & ~subtractor_result[31]) | (~b[31] & subtractor_result[31]);
    assign subtractor_carry = adder_carry;

    // Overflow detection
    assign overflow_detect = (a[31] ^ b[31]) & (a[31] ^ adder_result[31]);

    // Output selection
    assign result = (aluc == 6'b000000) ? add_result :
                    (aluc == 6'b000001) ? sub_result :
                    (aluc == 6'b000010) ? and_result :
                    (aluc == 6'b000011) ? or_result :
                    (aluc == 6'b000100) ? xor_result :
                    (aluc == 6'b000101) ? sl_result :
                    (aluc == 6'b000110) ? sr_result :
                    (aluc == 6'b000111) ? sra_result :
                    (aluc == 6'b001000) ? lui_result :
                    32'b0;

    // Flags
    assign zero = (result == 32'b0);
    assign carry = (aluc == 6'b000000) ? adder_carry :
                   (aluc == 6'b000001) ? subtractor_carry :
                   1'b0;
    assign negative = (result[31] == 1'b1);
    assign overflow = (overflow_detect == 1'b1);
    assign flag = (aluc == 6'b000000) ? adder_result[0] :
                  (aluc == 6'b000001) ? subtractor_result[0] :
                  1'b0;

    // Output
    assign r = result;

endmodule
